from agent import *from models.products import *def run(context, session):    session.queue(Request('http://iszene.com/forum-244.html', use='curl'), process_revlist, {})def process_revlist(data, context, session):    revs = data.xpath("//div[@data-rate-thread='1']//span[@class='subject_new']/a")    for rev in revs:        name = rev.xpath(".//text()").string()        url = rev.xpath("@href").string()        if '[Review]' in name or '[review]' in name:            session.queue(Request(url, use='curl'), process_product, dict(context, name=name, url=url))        next_url = data.xpath("//a[@class='pagination_next']/@href").string()    if next_url:        session.queue(Request(next_url, use='curl'), process_revlist, dict(context))def process_product(data, context, session):    product = Product()    product.ssid = context['url'].split('/')[-1].split('.html')[0]    product.url = context['url']    product.category = data.xpath("(//ol[@class='breadcrumb container']/li/a//text())[last()]").string()    name = context['name']    if 'eview] ' in name:        name = name.split('eview] ')[1]    product.name = name        review = Review()    review.title = context['name']    review.ssid = product.ssid    review.type = 'user'    review.url = context['url']    date = data.xpath("//div[@class='post_head']/span[@class='post_date']/text()").string()    if date:        review.date = date.split(',')[0]        author = data.xpath("//div[@class='author_information']/strong/span[@class='largetext']//text()").string()    review.authors.append(Person(name=author, ssid=author))    excerpt = data.xpath("(//div[@class='post_content']/div[@id])[1]/text()").string(multiple=True)    if excerpt:        if 'mycodepack_parse_table' in excerpt:            return # Broken page                review.properties.append(ReviewProperty(type='excerpt', value=excerpt))        grade_overall = data.xpath("//img[contains(@src,'https://iszene.com/images/iszene/star') and not(contains(@src,'_'))]/@src").string()    if grade_overall:        grade_overall = grade_overall.split('star')[1].split('.')[0]        if grade_overall and grade_overall > 0:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))        if excerpt:        product.reviews.append(review)        session.emit(product)